def find_barry_episode(episodes):
    """
    Searches a list of Barry episodes and returns details for 'A Nice Meal'.

    Args:
        episodes: List of dictionaries where each dict contains 'title', 'season', and 'episode_number'.

    Returns:
        Dictionary with title, season, and episode_number if found, otherwise None.
    """
    for episode in episodes:
        if episode.get('title').lower() == 'a nice meal':
            return {
                'title': episode['title'],
                'season': episode['season'],
                'episode_number': episode['episode_number']
            }
    return None

# Example usage:
episodes = [
    {'title': 'The Rock', 'season': 4, 'episode_number': 1},
    {'title': 'A Nice Meal', 'season': 4, 'episode_number': 7},
    {'title': 'The Signup', 'season': 4, 'episode_number': 8}
]

result = find_barry_episode(episodes)
print(result)  # Output: {'title': 'A Nice Meal', 'season': 4, 'episode_number': 7}
